module top_module(
  input clk,
  input reset,
  output reg [3:0] count
);reg [3:0] obf_temp_count;

always @ (posedge clk or negedge reset) begin
  if (!reset) begin
    obf_temp_count <= 4'b0000;
  end else begin
    obf_temp_count <= obf_temp_count + 4'b0001;
  end
end

assign count = obf_temp_count;

endmodule
